import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.D5wUhsuj.js";const h=JSON.parse('{"title":"Admin Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"admin/index.md","filePath":"admin/index.md","lastUpdated":1783546178000}'),n={name:"admin/index.md"};function i(s,t,d,l,p,c){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="admin-documentation" tabindex="-1">Admin Documentation <a class="header-anchor" href="#admin-documentation" aria-label="Permalink to &quot;Admin Documentation&quot;">​</a></h1><p>Admin documentation covers installation planning, platform configuration, user and workspace administration, operations, upgrades, and troubleshooting.</p><p>Use these pages when you operate a prokube deployment, connect it to organizational infrastructure, or expose custom workloads through the platform. User-facing concepts that apply across Labs, MLOps, and AgentOps are documented under <a href="./../platform/">Foundation</a>.</p><h2 id="what-admins-own" tabindex="-1">What Admins Own <a class="header-anchor" href="#what-admins-own" aria-label="Permalink to &quot;What Admins Own&quot;">​</a></h2><ul><li>deployment prerequisites such as Kubernetes, DNS, TLS, storage, identity, and registry access;</li><li>workspace, user, group, and network-policy administration;</li><li>external identity-provider and custom application integration;</li><li>capacity-sensitive resources such as storage, GPUs, databases, and object storage;</li><li>backup, restore, upgrade, observability, and incident runbooks.</li></ul><h2 id="available-pages" tabindex="-1">Available Pages <a class="header-anchor" href="#available-pages" aria-label="Permalink to &quot;Available Pages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>Use it for</th></tr></thead><tbody><tr><td><a href="./installation.html">Installation Planning</a></td><td>Planning Kubernetes, DNS, TLS, identity, registry, and storage prerequisites before installation.</td></tr><tr><td><a href="./user_management.html">User Management</a></td><td>Managing users, workspaces, groups, workspace access, and workspace security policy settings.</td></tr><tr><td><a href="./identity_providers.html">Identity Providers</a></td><td>Connecting external SSO providers to Keycloak and troubleshooting login/group mapping.</td></tr><tr><td><a href="./network_policies.html">Network Policies</a></td><td>Defining reusable egress profiles and assigning outbound network restrictions to workspaces.</td></tr><tr><td><a href="./application_networking.html">Application Networking</a></td><td>Exposing custom applications through prokube gateways and Istio routing.</td></tr><tr><td><a href="./application_authentication.html">Application Authentication</a></td><td>Choosing gateway authentication or direct OIDC for custom applications.</td></tr><tr><td><a href="./storage.html">Storage</a></td><td>Understanding StorageClasses, local storage, replicated storage, and PVC troubleshooting.</td></tr><tr><td><a href="./gpu.html">GPU Administration</a></td><td>Operating GPU nodes, NVIDIA GPU Operator, timeslicing, MIG, and GPU monitoring.</td></tr><tr><td><a href="./backup_restore.html">Backup and Restore</a></td><td>Disaster-recovery scope, backup storage, restore expectations, and validation.</td></tr><tr><td><a href="./upgrading.html">Upgrading</a></td><td>Planning release upgrades, GitOps-driven rollout, and post-upgrade validation.</td></tr><tr><td><a href="./operations_runbooks.html">Operations Runbooks</a></td><td>Administrator runbooks for MinIO, Keycloak bootstrap, and observability operations.</td></tr><tr><td><a href="./../platform/system_status.html">System Status</a></td><td>Checking administrator-only backend component health and backend metadata; the same page also shows workspace pod quota to all users.</td></tr></tbody></table><p>Platform-wide metrics, dashboards, alerts, and log-retention configuration remain administrator/operator topics. Use <a href="./../platform/system_status.html">System Status</a> for quick backend health checks, then use the deployment&#39;s Grafana, Prometheus, Alertmanager, and Loki tools for detailed monitoring.</p>',8)])])}const m=a(n,[["render",i]]);export{h as __pageData,m as default};
